using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change: discriminator renamed from "Discriminator" to "$type"
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer includes discriminator prefix ("Blog|1" → "1")
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id",
            // removing the separate "Id" property from the document
            b.HasShadowId();
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

